module top_module(
    input in1, in2, in3, in4,
    output out
);reg all_zero_flag;

    always @(*) begin
        case ({in1, in2, in3, in4})
            {1'b0, 1'b0, 1'b0, 1'b0}: all_zero_flag = 1'b1;
            default: all_zero_flag = 1'b0;
        endcase
    end

    assign out = all_zero_flag;

endmodule
